                writer.WriteString("identificadorClienteBanco", historicoResultadoRegistrosFInner.IdentificadorClienteBanco);

            if (historicoResultadoRegistrosFInner.IdentificadorRegistroEOption.IsSet)
                writer.WriteNumber("identificadorRegistroE", historicoResultadoRegistrosFInner.IdentificadorRegistroEOption.Value!.Value);

            var movimentoRawValue = HistoricoResultadoRegistrosFInner.MovimentoEnumToJsonValue(historicoResultadoRegistrosFInner.MovimentoOption.Value!.Value);
            writer.WriteString("movimento", movimentoRawValue);
            if (historicoResultadoRegistrosFInner.DataOption.IsSet)
                writer.WriteString("data", historicoResultadoRegistrosFInner.DataOption.Value!.Value.ToString(DataFormat));

            if (historicoResultadoRegistrosFInner.EnvioParceiroOption.IsSet)
                writer.WriteBoolean("envioParceiro", historicoResultadoRegistrosFInner.EnvioParceiroOption.Value!.Value);

            if (historicoResultadoRegistrosFInner.DataVencimentoOption.IsSet)
                writer.WriteString("dataVencimento", historicoResultadoRegistrosFInner.DataVencimentoOption.Value!.Value.ToString(DataVencimentoFormat));

            if (historicoResultadoRegistrosFInner.SituacaoOption.IsSet)
                writer.WriteString("situacao", historicoResultadoRegistrosFInner.Situacao);

            if (historicoResultadoRegistrosFInner.AutenticacaoOption.IsSet)
                writer.WriteString("autenticacao", historicoResultadoRegistrosFInner.Autenticacao);
        }
    }
}
